class Solution:
    def findRestaurant(self, list1: List[str], list2: List[str]) -> List[str]:
        idx = {w:i for i,w in enumerate(list1)}
        best = 10**9
        ans = []
        for j, w in enumerate(list2):
            if w in idx:
                s = idx[w] + j
                if s < best:
                    best = s
                    ans = [w]
                elif s == best:
                    ans.append(w)
        return ans

